SELECT DISTINCT date
FROM bus_ridership
ORDER BY date ASC;

SELECT SUM(passenger_cnt) AS total_passengers
  FROM bus_ridership
  WHERE stop_id = 0;

SELECT fare_revenue
FROM bus_ridership
WHERE date = '2015-01-01';

SELECT AVG(br.fare_revenue) AS overall_avg_fare_revenue
FROM bus_ridership br
INNER JOIN holiday_data hd ON br.date = hd.date;

SELECT MAX(passenger_cnt) AS max_passengers
FROM bus_ridership
WHERE route_id = 1 AND date = '2015-01-01';
